using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
namespace BackendAssignment3.Controllers {
//TODO: Add proper swagger comments to all endpoints.
public class FilesController : ControllerBase
    {
        private readonly ILogger<FilesController> _logger;

        public FilesController(ILogger<FilesController> logger)
        {
            this._logger = logger ?? throw new ArgumentNullException("logger");
        }
        [HttpPost]
        public ActionResult Upload([FromForm] IFormFile file, [FromQuery] string fileType)
        {
            try
            {
                //TODO: check that the supplied file name is unique.

                var directoryName = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads");
                 //TODO: Make a separate directory for each document type and use that as target folder
                if (!Directory.Exists(directoryName))
                    Directory.CreateDirectory(directoryName);
                var fileName = file.FileName;

                var filePath = Path.Combine(directoryName, fileName);
                using (var stream = new FileStream(filePath, FileMode.Create))
                {
                    file.CopyToAsync(stream).Wait();
                }
                
                //TODO: Upload files and return the file name only. 
                return Ok(fileName + fileType);
            }
            catch (Exception e)
            {
                this._logger.LogError("Exception in uploading file: " +e );
                return BadRequest(e);
            }
            
        }
    }
}